import numpy as np

class AttentionMechanismValidator:
    def __init__(self, model):
        self.model = model

    def validate_output(self, input_data, expected_output):
        # 获取模型预测结果
        predicted_output = self.model.predict(input_data)

        # 比较实际输出和预期输出
        if np.array_equal(predicted_output, expected_output):
            return True
        else:
            return False

